CREATE MATERIALIZED VIEW public.grants_mv AS
 SELECT ge.id AS grant_id,
    pgc.profiles_id AS grantor_id,
    ee.id AS emulation_id,
    pec.profiles_id AS emulated_id,
    ge.session_id AS grant_session_id,
    ee.session_id AS emulation_session_id,
    ge.expires_at,
    ge.used_at,
    ge.revoked_at,
    ge.created_at
   FROM (((public.grants_entry ge
     LEFT JOIN public.profiles_grants_connection pgc ON (((pgc.grant_id = ge.id) AND (pgc.active = true))))
     LEFT JOIN public.emulations_entry ee ON ((ee.grant_id = ge.id)))
     LEFT JOIN public.profiles_emulations_connection pec ON (((pec.emulation_id = ee.id) AND (pec.active = true))))
  WITH NO DATA;


